// src/pages/LeaveRequests.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

export default function LeaveRequests() {
  const { leaveRequests, setLeaveRequests, currentUser } = useApp();
  const [filter, setFilter] = useState('all');

  // Staff ko sirf unki assigned requests dikhenge, Admin ko sab
  const visibleRequests = leaveRequests.filter(r => {
    if (currentUser.role === 'admin') return true;
    return r.assignedTo === currentUser.name || r.applicant === currentUser.name;
  });

  const handleAccept = (id) => {
    setLeaveRequests(prev =>
      prev.map(r =>
        r.id === id
          ? { ...r, status: 'Approved', approvedBy: currentUser.name }
          : r
      )
    );
  };

  const handleReject = (id) => {
    setLeaveRequests(prev =>
      prev.map(r =>
        r.id === id
          ? { ...r, status: 'Rejected', approvedBy: currentUser.name }
          : r
      )
    );
  };

  return (
    <div style={{ padding: 30, maxWidth: 900, margin: '0 auto' }}>
      <h2>Leave Requests</h2>
      <div style={{ display: 'flex', gap: 10, marginBottom: 20 }}>
        {['all', 'pending', 'approved', 'rejected'].map(f => (
          <button key={f} onClick={() => setFilter(f)}>{f.toUpperCase()}</button>
        ))}
      </div>

      {visibleRequests.filter(r => filter==='all' || r.status===filter).map(r => (
        <div key={r.id} style={{ border: '1px solid #ccc', padding: 15, marginBottom: 10 }}>
          <div><strong>Applicant:</strong> {r.applicant}</div>
          <div><strong>Assigned To:</strong> {r.assignedTo}</div>
          <div><strong>Status:</strong> {r.status} {r.approvedBy && `(By ${r.approvedBy})`}</div>
          <div><strong>From:</strong> {r.fromDate} <strong>To:</strong> {r.toDate}</div>
          <div><strong>Reason:</strong> {r.reason}</div>

          {r.status === 'Pending' && (currentUser.name === r.assignedTo || currentUser.role==='admin') && (
            <div style={{ marginTop: 10, display: 'flex', gap: 10 }}>
              <button onClick={() => handleAccept(r.id)}>✅ Accept</button>
              <button onClick={() => handleReject(r.id)}>❌ Reject</button>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}
const styles = {
  container: { padding: 32, maxWidth: 1100, margin: '0 auto' },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', marginBottom: 24 },
  tabs: { display: 'flex', gap: 8, marginBottom: 24 },
  tab: {
    display: 'flex', alignItems: 'center', gap: 8,
    background: '#fff', border: '1.5px solid #e2e8f0',
    padding: '10px 20px', borderRadius: 12, cursor: 'pointer',
    fontSize: 14, fontWeight: 600, color: '#64748b', transition: 'all 0.2s',
  },
  tabActive: { background: '#1e293b', color: '#fff', borderColor: '#1e293b' },
  count: { background: 'rgba(255,255,255,0.2)', borderRadius: 20, padding: '2px 8px', fontSize: 12 },
  list: { display: 'flex', flexDirection: 'column', gap: 16 },
  card: { background: '#fff', borderRadius: 20, padding: 24, boxShadow: '0 2px 20px rgba(0,0,0,0.06)', border: '1px solid #f1f5f9' },
  cardHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' },
  leftInfo: { display: 'flex', gap: 16, alignItems: 'flex-start' },
  avatar: { width: 48, height: 48, borderRadius: '50%', flexShrink: 0, background: 'linear-gradient(135deg, #63b3ed, #9f7aea)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 700, fontSize: 20 },
  teacherName: { fontWeight: 800, fontSize: 16, color: '#1e293b' },
  dates: { color: '#3b82f6', fontSize: 14, fontWeight: 600, marginTop: 4 },
  reason: { color: '#64748b', fontSize: 13, marginTop: 4 },
  meta: { color: '#94a3b8', fontSize: 12, marginTop: 4 },
  rightActions: { display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 10 },
  actionBtns: { display: 'flex', gap: 8 },
  approveBtn: { background: '#10b981', color: '#fff', border: 'none', padding: '8px 18px', borderRadius: 10, cursor: 'pointer', fontWeight: 600, fontSize: 13 },
  rejectBtn: { background: '#ef4444', color: '#fff', border: 'none', padding: '8px 18px', borderRadius: 10, cursor: 'pointer', fontWeight: 600, fontSize: 13 },
  detailBtn: { background: '#f8fafc', border: '1px solid #e2e8f0', color: '#64748b', padding: '6px 14px', borderRadius: 10, cursor: 'pointer', fontSize: 13 },
  subSection: { marginTop: 20, borderTop: '1px solid #f1f5f9', paddingTop: 20 },
  subTitle: { fontWeight: 700, fontSize: 16, color: '#1e293b', marginBottom: 16 },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { background: '#f8fafc', padding: '10px 14px', textAlign: 'left', fontSize: 12, fontWeight: 700, color: '#64748b', borderRadius: 4 },
  tr: { borderBottom: '1px solid #f1f5f9' },
  td: { padding: '12px 14px', fontSize: 14, color: '#374151' },
  periodBadge: { background: '#dbeafe', color: '#1d4ed8', borderRadius: 8, padding: '3px 10px', fontWeight: 700, fontSize: 13 },
  noSub: { color: '#dc2626', fontSize: 13, fontWeight: 600 },
  subSelect: { padding: '6px 12px', borderRadius: 8, border: '1.5px solid #e2e8f0', fontSize: 13, color: '#374151', cursor: 'pointer', minWidth: 200 },
  empty: { background: '#f8fafc', borderRadius: 16, padding: 60, textAlign: 'center', color: '#94a3b8', fontSize: 15 },
  assigned: { color: 'green', fontWeight: 600 },
  waiting: { color: '#f59e0b', fontWeight: 600 },
  acceptBtn: { background: '#16a34a', color: '#fff', border: 'none', padding: '6px 14px', borderRadius: 6, cursor: 'pointer' },
};
